# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
import os
import secrets
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///password_reset.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    reset_token = db.Column(db.String(120), nullable=True)

@app.route('/reset_password', methods=['POST'])
def reset_password():
    data = request.get_json()
    user_email = data.get('email')

    if not user_email:
        return jsonify({'error': 'Email is required'}), 400

    user = User.query.filter_by(email=user_email).first()

    if not user:
        return jsonify({'error': 'User not found'}), 404

    reset_token = secrets.token_urlsafe(16)
    user.reset_token = reset_token
    db.session.commit()

    # Send email with the reset link here
    reset_link = f"http://example.com/reset?token={reset_token}"
    send_email(user_email, reset_link)

    return jsonify({'message': 'Password reset email sent'}), 200

def send_email(email, reset_link):
    # Implement your email sending logic here
    print(f"Sending password reset email to {email} with link: {reset_link}")

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)